import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Пошук надійних модів","description":"Інструкція із пошуку модів Fabric за допомогою надійних джерел.","frontmatter":{"title":"Пошук надійних модів","description":"Інструкція із пошуку модів Fabric за допомогою надійних джерел.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"uk_ua/players/finding-mods.md","filePath":"translated/uk_ua/players/finding-mods.md","lastUpdated":1770561656000}`);var a={name:`uk_ua/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Пошук надійних модів <a class="header-anchor" href="#h1" aria-label="Permalink to “Пошук надійних модів”">​</a></h1><p>По-перше, довіра суб’єктивна, і ви завжди повинні керуватися власним судженням, завантажуючи моди. Однак є деякі речі, які ви можете зробити, щоб допомогти вам знайти надійні моди.</p><h2 id="trustworthy-source" tabindex="-1">1. Використовуйте джерело, яке заслуговує довіри <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. Використовуйте джерело, яке заслуговує довіри”">​</a></h2><p>Більшість авторів публікують свої моди на <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> та <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Ці сайти перевіряють, чи моди є такими, якими вони є, і чи не містять вони шкідливого коду. Ви також можете повідомити про шкідливі моди на цих сайтах, і вони відносно швидко вживуть заходів.</p><h2 id="with-others" tabindex="-1">2. Зверніться до інших! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Зверніться до інших!”">​</a></h2><p>Якщо ви завантажуєте мод з джерела, яке, як відомо, не заслуговує довіри, вам слід перевірити в інших, чи завантажували вони моди раніше з того місця, звідки ви завантажуєте, і чи виникали у них проблеми з цим.</p><p>Якщо ви сумніваєтесь, ви завжди можете запитати в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord Fabric</a> в каналі <code>#player-support</code>.</p><h2 id="avoid-malware" tabindex="-1">3. Уникайте поширених сторінок зі шкідливим програмним забезпеченням! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Уникайте поширених сторінок зі шкідливим програмним забезпеченням!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Подібні сайти можуть бути не очевидними для всіх. Якщо ви не впевнені, ви можете запитати думки інших або покладатися лише на перевірені джерела, такі як Modrinth та Curseforge.</p></div><p>Існує багато сайтів, які стверджують, що мають моди для Minecraft, але насправді це лише сайти з вірусами. Вам слід оминати подібні сайти.</p><p>Ви можете використовувати антивіруси або сайти, такі як <a href="https://www.microsoft.com/uk-ua/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> або <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> щоб перевіряти завантажені моди. Але не покладайтеся повністю на них, тому що вони не завжди коректні.</p><p>Знову ж таки, якщо ви сумніваєтеся, ви можете запитати в <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord Fabric</a> в каналі <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};